    SELECT UserId FROM users ORDER BY Reputation DESC LIMIT 1
),
TotalPosts AS (
    SELECT COUNT(*) AS Total FROM posts WHERE OwnerUserId IN (SELECT UserId FROM TopUser)
),
HighScorePosts AS (
    SELECT COUNT(*) AS HighScore FROM posts WHERE OwnerUserId IN (SELECT UserId FROM TopUser) AND Score > 50
)
SELECT CAST(HighScore AS REAL) * 100 / Total AS Percentage
FROM HighScorePosts, TotalPosts;

WITH TopUser AS (
    SELECT TOP 1 Id, Reputation FROM users ORDER BY Reputation DESC
),
PostsByTopUser AS (
    SELECT * FROM posts WHERE OwnerUserId = (SELECT Id FROM TopUser)
)
